        // Images are omitted from output when skipImages is true
        val options = MAPPER.readValue("{\"skip_images\":true}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>Before <img src='test.jpg' alt='photo'> After</p>", options)
        assertTrue(result.content().orEmpty().contains("Before"), "expected to contain: " + "Before")
        assertTrue(result.content().orEmpty().contains("After"), "expected to contain: " + "After")
        assertFalse(result.content().orEmpty().contains("photo"), "expected NOT to contain: " + "photo")
    }

    @Test
    fun testOptionsStripNewlines() {
        // Strip newlines produces single-line paragraphs
        val options = MAPPER.readValue("{\"strip_newlines\":true}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>First paragraph.</p><p>Second paragraph.</p>", options)
        assertTrue(result.content().orEmpty().contains("First paragraph."), "expected to contain: " + "First paragraph.")
        assertTrue(result.content().orEmpty().contains("Second paragraph."), "expected to contain: " + "Second paragraph.")
    }

    @Test
    fun testOptionsStripTagsDivSpan() {
        // Div and span tags stripped but content preserved
        val options = MAPPER.readValue("{\"strip_tags\":[\"div\",\"span\"]}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<div class='wrapper'><p>Inside div</p></div><p>Outside <span class='hl'>span text</span></p>", options)
        assertTrue(result.content().orEmpty().contains("Inside div"), "expected to contain: " + "Inside div")
        assertTrue(result.content().orEmpty().contains("span text"), "expected to contain: " + "span text")
    }

    @Test
    fun testOptionsStrongEmUnderscore() {
        // Strong and em tags use underscore symbol instead of asterisk
        val options = MAPPER.readValue("{\"strong_em_symbol\":\"_\"}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p><strong>bold</strong> and <em>italic</em></p>", options)
        assertTrue(result.content().orEmpty().contains("__bold__"), "expected to contain: " + "__bold__")
        assertTrue(result.content().orEmpty().contains("_italic_"), "expected to contain: " + "_italic_")
    }

    @Test
    fun testOptionsSubSymbolTilde() {
        // Subscript rendered with tilde symbol
        val options = MAPPER.readValue("{\"sub_symbol\":\"~\"}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>H<sub>2</sub>O</p>", options)
        assertTrue(result.content().orEmpty().contains("~2~"), "expected to contain: " + "~2~")
    }

    @Test
    fun testOptionsSupSymbolCaret() {
        // Superscript rendered with caret symbol
        val options = MAPPER.readValue("{\"sup_symbol\":\"^\"}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>x<sup>2</sup></p>", options)
        assertTrue(result.content().orEmpty().contains("^2^"), "expected to contain: " + "^2^")
    }

    @Test
    fun testOptionsWhitespaceNormalized() {
        // Normalized whitespace mode collapses multiple spaces
        val options = MAPPER.readValue("{\"whitespace_mode\":\"Normalized\"}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>Text   with    extra   spaces.</p>", options)
        assertTrue(result.content() != null, "expected non-empty value")
        assertTrue(result.content().orEmpty().contains("Text"), "expected to contain: " + "Text")
        assertTrue(result.content().orEmpty().contains("with"), "expected to contain: " + "with")
        assertTrue(result.content().orEmpty().contains("extra"), "expected to contain: " + "extra")
        assertTrue(result.content().orEmpty().contains("spaces."), "expected to contain: " + "spaces.")
    }

    @Test
    fun testOptionsWhitespaceStrict() {
        // Strict whitespace mode preserves whitespace as-is
        val options = MAPPER.readValue("{\"whitespace_mode\":\"Strict\"}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>Preserved   spacing.</p>", options)
        assertTrue(result.content() != null, "expected non-empty value")
        assertTrue(result.content().orEmpty().contains("Preserved"), "expected to contain: " + "Preserved")
        assertTrue(result.content().orEmpty().contains("spacing."), "expected to contain: " + "spacing.")
    }

    @Test
    fun testOptionsWrapDisabled() {
        // Wrap option disabled preserves long lines without breaking
        val options = MAPPER.readValue("{\"wrap\":false}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>This is a long paragraph that should not be wrapped at all because wrapping is disabled.</p>", options)
        assertTrue(result.content().orEmpty().contains("This is a long paragraph that should not be wrapped at all because wrapping is disabled."), "expected to contain: " + "This is a long paragraph that should not be wrapped at all because wrapping is disabled.")
    }

    @Test
    fun testOptionsWrapEnabled() {
        // Wrap option enabled with custom width wraps long lines
        val options = MAPPER.readValue("{\"wrap\":true,\"wrap_width\":40}", ConversionOptions::class.java)
        val result = HtmlToMarkdownAndroid.convert("<p>This is a long paragraph that should be wrapped at the specified column width when the wrap option is enabled.</p>", options)
        assertTrue(result.content() != null, "expected non-empty value")
        assertTrue(result.content().orEmpty().contains("This is a long paragraph"), "expected to contain: " + "This is a long paragraph")
    }

}
